let puppeteer=require("puppeteer"),fs=require("fs"),path=require("path"),BASE_URL="http://localhost:8080",EXCLUDE_PATTERNS=["/admin","/login","/logout","/signup","/register","/account","/dashboard","/api",".pdf",".zip",".jpg",".png",".gif"],MAX_PAGES=100,OUTPUT_FILE=path.join(__dirname,"pages-to-test.json");function shouldExclude(e){if(!e.startsWith(BASE_URL))return!0;for(var t of EXCLUDE_PATTERNS)if(e.includes(t))return!0;return!1}function normalizeUrl(e){e=e.split("?")[0].split("#")[0];return e.endsWith("/")?e.slice(0,-1):e}async function crawlWebsite(){var e=await puppeteer.launch(),t=await e.newPage(),r=(await t.setViewport({width:1280,height:800}),[BASE_URL]),a=new Set,i=new Set([BASE_URL]);for(console.log("Starting crawl from "+BASE_URL);0<r.length&&a.size<MAX_PAGES;){var o,s=normalizeUrl(r.shift());if(!a.has(s)){console.log(`Visiting ${s} (${a.size+1}/${MAX_PAGES})`);try{await t.goto(s,{waitUntil:"networkidle2",timeout:3e4}),a.add(s);for(o of await t.evaluate(()=>Array.from(document.querySelectorAll("a[href]")).map(e=>e.href).filter(e=>e&&!e.startsWith("javascript:")&&!e.startsWith("mailto:")&&!e.startsWith("tel:")))){var n=normalizeUrl(o);shouldExclude(n)||a.has(n)||i.has(n)||(i.add(n),r.push(n))}}catch(e){console.error(`Error visiting ${s}: `+e.message)}}}await e.close();e=Array.from(a);return console.log(`Crawl complete. Found ${e.length} pages.`),e}async function main(){try{var e=await crawlWebsite();fs.writeFileSync(OUTPUT_FILE,JSON.stringify(e,null,2)),console.log(`Wrote ${e.length} URLs to `+OUTPUT_FILE)}catch(e){console.error("Error: "+e.message),process.exit(1)}}main();